import{_ as e,c as a,o as i,a1 as n}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"7-Stage Pipeline Overview: From Bootstrap to Preview Complete Process Guide | AI App Factory Tutorial","description":"Learn the complete AI App Factory pipeline from Bootstrap structured product ideas to Preview deployment guide. Master checkpoint mechanism, permission control, and failure handling.","frontmatter":{"title":"7-Stage Pipeline Overview: From Bootstrap to Preview Complete Process Guide | AI App Factory Tutorial","sidebarTitle":"7-Stage Pipeline Overview","subtitle":"7-Stage Pipeline Overview","description":"Learn the complete AI App Factory pipeline from Bootstrap structured product ideas to Preview deployment guide. Master checkpoint mechanism, permission control, and failure handling.","tags":["Pipeline","Sisyphus","Agent"],"prerequisite":["start-init-project"],"order":40},"headers":[],"relativePath":"hyz1992/agent-app-factory/start/pipeline-overview/index.md","filePath":"hyz1992/agent-app-factory/start/pipeline-overview/index.md"}'),s={name:"hyz1992/agent-app-factory/start/pipeline-overview/index.md"};function o(r,t,d,l,c,p){return i(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="_7-stage-pipeline-overview" tabindex="-1">7-Stage Pipeline Overview <a class="header-anchor" href="#_7-stage-pipeline-overview" aria-label="Permalink to &quot;7-Stage Pipeline Overview&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><p>After completing this lesson, you will be able to:</p><ul><li>Understand the complete workflow of the 7-stage pipeline and the responsibilities of each stage</li><li>Know the input, output, and exit criteria for each stage</li><li>Understand how the checkpoint mechanism ensures quality</li><li>Understand how the Sisyphus scheduler coordinates Agent execution</li><li>Master how the permission matrix prevents Agents from overstepping</li><li>Learn to use &quot;continue in new session&quot; to save tokens</li></ul><h2 id="core-concept" tabindex="-1">Core Concept <a class="header-anchor" href="#core-concept" aria-label="Permalink to &quot;Core Concept&quot;">​</a></h2><p><strong>What is a pipeline?</strong></p><p>The AI App Factory pipeline is an automated production line that transforms your product idea step by step into a runnable application. Like a factory production line, raw materials (product ideas) pass through 7 processes (stages) to ultimately produce the finished product (complete application).</p><p>Each process is handled by a dedicated Agent, with clear responsibilities and no interference:</p><table tabindex="0"><thead><tr><th>Stage</th><th>Agent</th><th>Responsibility</th><th>Output</th></tr></thead><tbody><tr><td>Bootstrap</td><td>Bootstrap Agent</td><td>Deep dive into product ideas</td><td><code>input/idea.md</code></td></tr><tr><td>PRD</td><td>PRD Agent</td><td>Generate product requirements document</td><td><code>artifacts/prd/prd.md</code></td></tr><tr><td>UI</td><td>UI Agent</td><td>Design interface and prototype</td><td><code>artifacts/ui/ui.schema.yaml</code> + preview page</td></tr><tr><td>Tech</td><td>Tech Agent</td><td>Design technical architecture</td><td><code>artifacts/tech/tech.md</code> + Prisma Schema</td></tr><tr><td>Code</td><td>Code Agent</td><td>Generate runnable code</td><td><code>artifacts/backend/</code> + <code>artifacts/client/</code></td></tr><tr><td>Validation</td><td>Validation Agent</td><td>Verify code quality</td><td><code>artifacts/validation/report.md</code></td></tr><tr><td>Preview</td><td>Preview Agent</td><td>Generate deployment guide</td><td><code>artifacts/preview/README.md</code></td></tr></tbody></table><p><strong>Key Features</strong></p><ol><li><strong>Checkpoint Mechanism</strong>: Pause after each stage and wait for your confirmation before continuing</li><li><strong>Permission Isolation</strong>: Each Agent can only read/write authorized directories, preventing contamination</li><li><strong>Failure Rollback</strong>: Automatically retry on stage failure, rollback to last successful checkpoint on consecutive failures</li><li><strong>Context Optimization</strong>: Support continuing execution in a new session to save tokens</li></ol><h2 id="pipeline-overview" tabindex="-1">Pipeline Overview <a class="header-anchor" href="#pipeline-overview" aria-label="Permalink to &quot;Pipeline Overview&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[Bootstrap&lt;br/&gt;Structure Product Idea] --&gt;|idea.md| B[PRD&lt;br/&gt;Generate Requirements]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt;|prd.md| C[UI&lt;br/&gt;Design Interface Prototype]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|ui.schema.yaml| D[Tech&lt;br/&gt;Design Technical Architecture]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt;|tech.md + schema.prisma| E[Code&lt;br/&gt;Generate Runnable Code]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt;|backend + client| F[Validation&lt;br/&gt;Verify Code Quality]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt;|Validation Report| G[Preview&lt;br/&gt;Generate Deployment Guide]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style A fill:#e0f2fe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style B fill:#f0fdf4</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#fef3c7</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style D fill:#ede9fe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style E fill:#fce7f3</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style F fill:#dbeafe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style G fill:#d1fae5</span></span></code></pre></div><p><strong>Pipeline Execution Rules</strong></p><div class="tip custom-block"><p class="custom-block-title">Execution Rules</p><ol><li><strong>Strict Order</strong>: Must start from Bootstrap and execute sequentially to Preview, cannot skip or run in parallel</li><li><strong>Single Agent Activation</strong>: Only one Agent can work at a time</li><li><strong>No Backtracking</strong>: Confirmed artifacts cannot be modified, can only re-execute the stage</li></ol><p>Note: These are pipeline execution rules, not the number of checkpoint options. After each stage completes, Sisyphus provides 5 checkpoint options (see &quot;Checkpoint Mechanism&quot; section below).</p></div><h2 id="stage-details" tabindex="-1">Stage Details <a class="header-anchor" href="#stage-details" aria-label="Permalink to &quot;Stage Details&quot;">​</a></h2><h3 id="stage-1-bootstrap-structure-product-idea" tabindex="-1">Stage 1: Bootstrap - Structure Product Idea <a class="header-anchor" href="#stage-1-bootstrap-structure-product-idea" aria-label="Permalink to &quot;Stage 1: Bootstrap - Structure Product Idea&quot;">​</a></h3><p><strong>What it does</strong></p><p>Transforms your natural language product description into a structured document, deeply exploring problems, users, value, and assumptions.</p><p><strong>Why it&#39;s important</strong></p><p>A clear product definition is the foundation of the entire pipeline. If this step is not done well, all subsequent stages will go off track.</p><p><strong>Input and Output</strong></p><table tabindex="0"><thead><tr><th>Type</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td>Input</td><td>User natural language description</td><td>Example: &quot;I want to make a bookkeeping app&quot;</td></tr><tr><td>Output</td><td><code>input/idea.md</code></td><td>Structured product idea document</td></tr></tbody></table><p><strong>Exit Criteria</strong></p><ul><li>[ ] <code>idea.md</code> exists</li><li>[ ] Describes a coherent product idea</li><li>[ ] Agent used <code>superpowers:brainstorm</code> skill for deep exploration</li></ul><p><strong>Required Skill Usage</strong></p><div class="warning custom-block"><p class="custom-block-title">Must Use superpowers:brainstorm</p><p>The Bootstrap stage must use the <code>superpowers:brainstorm</code> skill for deep exploration. If the Agent does not mention using this skill, the artifact will be rejected and require re-execution.</p></div><h3 id="stage-2-prd-generate-product-requirements-document" tabindex="-1">Stage 2: PRD - Generate Product Requirements Document <a class="header-anchor" href="#stage-2-prd-generate-product-requirements-document" aria-label="Permalink to &quot;Stage 2: PRD - Generate Product Requirements Document&quot;">​</a></h3><p><strong>What it does</strong></p><p>Transforms the structured product idea into an MVP-level product requirements document, defining feature scope, non-goals, and user stories.</p><p><strong>Why it&#39;s important</strong></p><p>The PRD is the &quot;contract&quot; for design and development, clarifying &quot;what to do&quot; and &quot;what not to do,&quot; preventing scope creep.</p><p><strong>Input and Output</strong></p><table tabindex="0"><thead><tr><th>Type</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td>Input</td><td><code>input/idea.md</code></td><td>Structured idea from Bootstrap stage</td></tr><tr><td>Output</td><td><code>artifacts/prd/prd.md</code></td><td>MVP-level product requirements document</td></tr></tbody></table><p><strong>Exit Criteria</strong></p><ul><li>[ ] PRD includes target users</li><li>[ ] PRD defines MVP scope</li><li>[ ] PRD lists non-goals</li><li>[ ] PRD contains no technical implementation details</li></ul><p><strong>Note: PRD Should Not Include Technical Details</strong></p><p>The PRD should describe &quot;what users need,&quot; not &quot;how to implement.&quot; Technical implementation details are handled by the Tech and Code stages.</p><h3 id="stage-3-ui-design-interface-and-prototype" tabindex="-1">Stage 3: UI - Design Interface and Prototype <a class="header-anchor" href="#stage-3-ui-design-interface-and-prototype" aria-label="Permalink to &quot;Stage 3: UI - Design Interface and Prototype&quot;">​</a></h3><p><strong>What it does</strong></p><p>Designs UI structure and color schemes based on the PRD, and generates HTML prototypes that can be previewed in a browser.</p><p><strong>Why it&#39;s important</strong></p><p>Visual design lets the team and early users intuitively understand the product form, reducing development rework.</p><p><strong>Input and Output</strong></p><table tabindex="0"><thead><tr><th>Type</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td>Input</td><td><code>artifacts/prd/prd.md</code></td><td>PRD document</td></tr><tr><td>Output</td><td><code>artifacts/ui/ui.schema.yaml</code></td><td>UI structure definition</td></tr><tr><td>Output</td><td><code>artifacts/ui/preview.web/index.html</code></td><td>Previewable HTML prototype</td></tr></tbody></table><p><strong>Exit Criteria</strong></p><ul><li>[ ] <code>ui.schema.yaml</code> exists</li><li>[ ] Number of pages does not exceed 3</li><li>[ ] Preview page can be opened in a browser</li><li>[ ] Agent used <code>ui-ux-pro-max</code> skill</li></ul><p><strong>Required Skill Usage</strong></p><div class="warning custom-block"><p class="custom-block-title">Must Use ui-ux-pro-max</p><p>The UI stage must use the <code>ui-ux-pro-max</code> skill to generate a professional design system. This skill includes 67 styles, 96 color palettes, and 100 industry rules.</p></div><h3 id="stage-4-tech-design-technical-architecture" tabindex="-1">Stage 4: Tech - Design Technical Architecture <a class="header-anchor" href="#stage-4-tech-design-technical-architecture" aria-label="Permalink to &quot;Stage 4: Tech - Design Technical Architecture&quot;">​</a></h3><p><strong>What it does</strong></p><p>Designs a minimal viable technical architecture and data model, selects the tech stack, and defines API endpoints.</p><p><strong>Why it&#39;s important</strong></p><p>Technical architecture determines code maintainability, scalability, and performance. Over-design makes development difficult, while under-design cannot support requirements.</p><p><strong>Input and Output</strong></p><table tabindex="0"><thead><tr><th>Type</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td>Input</td><td><code>artifacts/prd/prd.md</code></td><td>PRD document</td></tr><tr><td>Output</td><td><code>artifacts/tech/tech.md</code></td><td>Technical architecture document</td></tr><tr><td>Output</td><td><code>artifacts/backend/prisma/schema.prisma</code></td><td>Prisma data model</td></tr></tbody></table><p><strong>Exit Criteria</strong></p><ul><li>[ ] Tech stack explicitly declared</li><li>[ ] Data model consistent with PRD</li><li>[ ] No premature optimization or over-design</li></ul><p><strong>Default Tech Stack Choices</strong></p><ul><li>Backend: Node.js + Express + Prisma</li><li>Database: SQLite (development) / PostgreSQL (production)</li><li>Frontend: React Native + Expo</li></ul><h3 id="stage-5-code-generate-runnable-code" tabindex="-1">Stage 5: Code - Generate Runnable Code <a class="header-anchor" href="#stage-5-code-generate-runnable-code" aria-label="Permalink to &quot;Stage 5: Code - Generate Runnable Code&quot;">​</a></h3><p><strong>What it does</strong></p><p>Generates complete frontend and backend code, tests, configuration, and documentation based on UI Schema, Tech design, and Prisma Schema.</p><p><strong>Why it&#39;s important</strong></p><p>This is the key step from &quot;idea to application,&quot; generating runnable, production-ready code.</p><p><strong>Input and Output</strong></p><table tabindex="0"><thead><tr><th>Type</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td>Input</td><td><code>artifacts/ui/ui.schema.yaml</code></td><td>UI structure definition</td></tr><tr><td>Input</td><td><code>artifacts/tech/tech.md</code></td><td>Technical architecture document</td></tr><tr><td>Input</td><td><code>artifacts/backend/prisma/schema.prisma</code></td><td>Data model</td></tr><tr><td>Output</td><td><code>artifacts/backend/</code></td><td>Backend code (Express + Prisma)</td></tr><tr><td>Output</td><td><code>artifacts/client/</code></td><td>Frontend code (React Native)</td></tr></tbody></table><p><strong>Exit Criteria</strong></p><ul><li>[ ] Backend can start without major errors</li><li>[ ] Client can render and be accessed</li><li>[ ] No additional authentication or unrelated features introduced</li></ul><p><strong>Generated Content</strong></p><p>The Code Agent generates the following:</p><p><strong>Backend</strong>:</p><ul><li>Express server + routes</li><li>Prisma ORM + data model</li><li>Unit tests and integration tests (Vitest)</li><li>API documentation (Swagger/OpenAPI)</li><li>Seed data (<code>prisma/seed.ts</code>)</li><li>Docker configuration</li><li>Logging and monitoring</li></ul><p><strong>Frontend</strong>:</p><ul><li>React Native pages and components</li><li>React Navigation routing</li><li>Unit tests (Jest + React Testing Library)</li><li>Environment configuration</li></ul><div class="info custom-block"><p class="custom-block-title">Why Not Generate Authentication Features?</p><p>AI App Factory focuses on MVP and does not generate authentication, authorization, or other complex features by default. These can be added in subsequent iterations.</p></div><h3 id="stage-6-validation-verify-code-quality" tabindex="-1">Stage 6: Validation - Verify Code Quality <a class="header-anchor" href="#stage-6-validation-verify-code-quality" aria-label="Permalink to &quot;Stage 6: Validation - Verify Code Quality&quot;">​</a></h3><p><strong>What it does</strong></p><p>Verifies that the generated code can install dependencies normally, pass type checking, and comply with code standards.</p><p><strong>Why it&#39;s important</strong></p><p>Discover issues before running code to avoid discovering errors after deployment, saving debugging time.</p><p><strong>Input and Output</strong></p><table tabindex="0"><thead><tr><th>Type</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td>Input</td><td><code>artifacts/backend/</code></td><td>Backend code</td></tr><tr><td>Input</td><td><code>artifacts/client/</code></td><td>Frontend code</td></tr><tr><td>Output</td><td><code>artifacts/validation/report.md</code></td><td>Validation report</td></tr></tbody></table><p><strong>Exit Criteria</strong></p><ul><li>[ ] Validation report generated</li><li>[ ] Backend dependencies resolve successfully</li><li>[ ] Frontend dependencies resolve successfully</li><li>[ ] TypeScript compilation passes without serious errors</li><li>[ ] Prisma schema validation passes</li></ul><p><strong>Validation Content</strong></p><p>The Validation Agent checks:</p><ol><li><strong>Dependency Resolution</strong>: Does <code>npm install</code> succeed?</li><li><strong>Type Checking</strong>: Does <code>tsc --noEmit</code> pass?</li><li><strong>Code Standards</strong>: Does it comply with <code>policies/code-standards.md</code>?</li><li><strong>Prisma Schema</strong>: Does <code>prisma validate</code> pass?</li><li><strong>Test Pass Rate</strong>: Do tests exist and can they execute?</li></ol><p><strong>Failure Handling</strong></p><p>If validation fails, the Validation Agent generates a detailed error report pointing out specific issues and fix suggestions.</p><h3 id="stage-7-preview-generate-deployment-guide" tabindex="-1">Stage 7: Preview - Generate Deployment Guide <a class="header-anchor" href="#stage-7-preview-generate-deployment-guide" aria-label="Permalink to &quot;Stage 7: Preview - Generate Deployment Guide&quot;">​</a></h3><p><strong>What it does</strong></p><p>Summarizes all artifacts and generates complete run instructions, deployment configuration, and demo process documentation.</p><p><strong>Why it&#39;s important</strong></p><p>This is the final stage of the pipeline, allowing you to quickly run and deploy the generated application.</p><p><strong>Input and Output</strong></p><table tabindex="0"><thead><tr><th>Type</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td>Input</td><td><code>artifacts/backend/</code></td><td>Backend code</td></tr><tr><td>Input</td><td><code>artifacts/client/</code></td><td>Frontend code</td></tr><tr><td>Output</td><td><code>artifacts/preview/README.md</code></td><td>Complete run instructions</td></tr><tr><td>Output</td><td><code>artifacts/preview/GETTING_STARTED.md</code></td><td>Quick start guide</td></tr></tbody></table><p><strong>Exit Criteria</strong></p><ul><li>[ ] README includes installation steps</li><li>[ ] README includes run commands</li><li>[ ] README lists access URLs and demo process</li></ul><p><strong>Generated Content</strong></p><p>The Preview Agent generates:</p><ul><li>Local run instructions (Web, iOS, Android)</li><li>Docker deployment configuration (<code>docker-compose.yml</code>)</li><li>CI/CD configuration reference (GitHub Actions)</li><li>Git Hooks configuration reference (Husky)</li><li>Database migration guide (SQLite → PostgreSQL)</li></ul><h2 id="checkpoint-mechanism" tabindex="-1">Checkpoint Mechanism <a class="header-anchor" href="#checkpoint-mechanism" aria-label="Permalink to &quot;Checkpoint Mechanism&quot;">​</a></h2><p><strong>What is a checkpoint?</strong></p><p>After each stage completes, the pipeline pauses and displays a list of generated artifacts, allowing you to confirm whether they meet expectations. If not, you can choose &quot;retry&quot; or &quot;modify and re-run.&quot;</p><p><strong>Why do we need checkpoints?</strong></p><ul><li><strong>Prevent error accumulation</strong>: If early-stage problems are not resolved in the current stage, subsequent stages will amplify errors</li><li><strong>Ensure quality</strong>: Each stage ensures output meets expectations, avoiding generating unusable code</li><li><strong>Flexible control</strong>: You can pause, retry, or modify input at any checkpoint</li></ul><p><strong>Checkpoint Options</strong></p><p>After each stage completes, the Sisyphus scheduler displays the following options:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────┬──────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ Option │ Description                                          │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  1   │ Continue to next stage (same session)                 │</span></span>
<span class="line"><span>│      │ I will continue executing the [next stage name] stage │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  2   │ Continue in new session ⭐ Recommended, saves tokens  │</span></span>
<span class="line"><span>│      │ Execute in new terminal window: factory continue      │</span></span>
<span class="line"><span>│      │ (Will automatically start new Claude Code window and  │</span></span>
<span class="line"><span>│      │  continue pipeline)                                   │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  3   │ Rerun current stage                                   │</span></span>
<span class="line"><span>│      │ Re-execute the [current stage name] stage            │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  4   │ Modify artifacts and re-run                           │</span></span>
<span class="line"><span>│      │ Re-execute after modifying [some input file]         │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  5   │ Pause pipeline                                        │</span></span>
<span class="line"><span>│      │ Save current progress and continue later              │</span></span>
<span class="line"><span>└──────┴──────────────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>Recommended Practice</strong></p><div class="tip custom-block"><p class="custom-block-title">Choose &quot;Continue in New Session&quot; to Save Tokens</p><p>After each stage completes, it&#39;s recommended to choose &quot;Continue in new session&quot; (Option 2):</p><ol><li>Execute <code>factory continue</code> in a new terminal window</li><li>The command will automatically start a new Claude Code window</li><li>Each stage gets a clean context, avoiding token accumulation</li></ol></div><h2 id="permission-matrix" tabindex="-1">Permission Matrix <a class="header-anchor" href="#permission-matrix" aria-label="Permalink to &quot;Permission Matrix&quot;">​</a></h2><p><strong>Why do we need permission isolation?</strong></p><p>If Agents can arbitrarily read/write any directory, it could lead to:</p><ul><li>Bootstrap Agent accidentally modifying a completed PRD</li><li>Code Agent accidentally deleting UI design</li><li>Validation Agent mistakenly modifying backend code</li></ul><p><strong>Capability Boundary Matrix</strong></p><p>The Sisyphus scheduler checks Agent permissions before and after each stage execution:</p><table tabindex="0"><thead><tr><th>Agent</th><th>Can Read</th><th>Can Write</th></tr></thead><tbody><tr><td>bootstrap</td><td>None</td><td><code>input/</code></td></tr><tr><td>prd</td><td><code>input/</code></td><td><code>artifacts/prd/</code></td></tr><tr><td>ui</td><td><code>artifacts/prd/</code></td><td><code>artifacts/ui/</code></td></tr><tr><td>tech</td><td><code>artifacts/prd/</code></td><td><code>artifacts/tech/</code>, <code>artifacts/backend/prisma/</code></td></tr><tr><td>code</td><td><code>artifacts/ui/</code>, <code>artifacts/tech/</code>, <code>artifacts/backend/prisma/</code></td><td><code>artifacts/backend/</code>, <code>artifacts/client/</code></td></tr><tr><td>validation</td><td><code>artifacts/backend/</code>, <code>artifacts/client/</code></td><td><code>artifacts/validation/</code></td></tr><tr><td>preview</td><td><code>artifacts/backend/</code>, <code>artifacts/client/</code></td><td><code>artifacts/preview/</code></td></tr></tbody></table><p><strong>Permission Violation Handling</strong></p><p>If an Agent writes to an unauthorized directory, the Sisyphus scheduler moves the file to <code>artifacts/_untrusted/&lt;stage-id&gt;/</code>, pauses the pipeline, and reports.</p><div class="warning custom-block"><p class="custom-block-title">Permission Violation Example</p><p>Suppose the PRD Agent writes <code>artifacts/ui/ui.schema.yaml</code> (which is not within its permission scope). The scheduler will:</p><ol><li>Move the file to <code>artifacts/_untrusted/prd/ui.schema.yaml</code></li><li>Pause the pipeline</li><li>Report: Unauthorized write detected, please handle manually</li></ol></div><h2 id="failure-handling" tabindex="-1">Failure Handling <a class="header-anchor" href="#failure-handling" aria-label="Permalink to &quot;Failure Handling&quot;">​</a></h2><p><strong>What counts as failure?</strong></p><ul><li>Output file missing</li><li>Artifact content does not meet <code>exit_criteria</code></li><li>Agent wrote to unauthorized directory</li><li>Script error or unable to read input</li></ul><p><strong>Default Handling Strategy</strong></p><ol><li><strong>Auto Retry</strong>: Each stage allows one automatic retry</li><li><strong>Failure Archival</strong>: Failed artifacts are moved to <code>artifacts/_failed/&lt;stage-id&gt;/</code></li><li><strong>Pause Pipeline</strong>: After two consecutive failures, wait for manual intervention</li><li><strong>Rollback Mechanism</strong>: Rollback to the last successful checkpoint to re-execute</li></ol><div class="tip custom-block"><p class="custom-block-title">Handling After Manual Intervention</p><p>If there are two consecutive failures, you can:</p><ol><li>Modify input files (such as <code>input/idea.md</code>)</li><li>Adjust Agent prompts</li><li>Fix permission issues</li><li>Execute <code>factory run [stage]</code> to restart from that stage</li></ol></div><h2 id="state-management" tabindex="-1">State Management <a class="header-anchor" href="#state-management" aria-label="Permalink to &quot;State Management&quot;">​</a></h2><p><strong>State File</strong></p><p>All pipeline states are saved in <code>.factory/state.json</code>, including:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;version&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;status&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;waiting_for_confirmation&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;current_stage&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;prd&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;completed_stages&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bootstrap&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;started_at&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-01-29T10:00:00Z&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;last_updated&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-01-29T10:30:00Z&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>State Machine</strong></p><table tabindex="0"><thead><tr><th>State</th><th>Meaning</th><th>Trigger Condition</th></tr></thead><tbody><tr><td>idle</td><td>Not started</td><td>Waiting for <code>factory run</code></td></tr><tr><td>running</td><td>Executing</td><td>Started executing a Stage</td></tr><tr><td>waiting_for_confirmation</td><td>Waiting for confirmation</td><td>Stage completed</td></tr><tr><td>paused</td><td>Paused</td><td>User chose to pause</td></tr><tr><td>failed</td><td>Failed, needs intervention</td><td>Consecutive failures or unauthorized operations</td></tr></tbody></table><p>Only the Sisyphus scheduler has permission to update state.</p><h2 id="pitfall-alerts" tabindex="-1">Pitfall Alerts <a class="header-anchor" href="#pitfall-alerts" aria-label="Permalink to &quot;Pitfall Alerts&quot;">​</a></h2><h3 id="common-error-1-bootstrap-stage-did-not-use-brainstorm-skill" tabindex="-1">Common Error 1: Bootstrap Stage Did Not Use brainstorm Skill <a class="header-anchor" href="#common-error-1-bootstrap-stage-did-not-use-brainstorm-skill" aria-label="Permalink to &quot;Common Error 1: Bootstrap Stage Did Not Use brainstorm Skill&quot;">​</a></h3><p><strong>Symptom</strong>: Sisyphus refuses to accept <code>input/idea.md</code> and prompts &quot;Detected that superpowers:brainstorm skill was not used.&quot;</p><p><strong>Cause</strong>: Bootstrap Agent did not use the <code>superpowers:brainstorm</code> skill to deeply explore product ideas.</p><p><strong>Solution</strong>: When confirming artifacts, choose &quot;Rerun current stage&quot; and explicitly require the Agent to use the <code>superpowers:brainstorm</code> skill.</p><h3 id="common-error-2-ui-stage-design-is-mediocre" tabindex="-1">Common Error 2: UI Stage Design Is Mediocre <a class="header-anchor" href="#common-error-2-ui-stage-design-is-mediocre" aria-label="Permalink to &quot;Common Error 2: UI Stage Design Is Mediocre&quot;">​</a></h3><p><strong>Symptom</strong>: Generated UI designs all look the same—purple gradients and Inter fonts.</p><p><strong>Cause</strong>: UI Agent did not use the <code>ui-ux-pro-max</code> skill.</p><p><strong>Solution</strong>: When confirming artifacts, choose &quot;Rerun current stage&quot; and explicitly require the Agent to use the <code>ui-ux-pro-max</code> skill, specifying a distinct aesthetic direction (such as &quot;Cyberpunk&quot; or &quot;Minimalism&quot;).</p><h3 id="common-error-3-code-stage-generated-authentication-features" tabindex="-1">Common Error 3: Code Stage Generated Authentication Features <a class="header-anchor" href="#common-error-3-code-stage-generated-authentication-features" aria-label="Permalink to &quot;Common Error 3: Code Stage Generated Authentication Features&quot;">​</a></h3><p><strong>Symptom</strong>: Generated backend code includes JWT authentication, user login, and other complex features.</p><p><strong>Cause</strong>: Code Agent exceeded the MVP scope.</p><p><strong>Solution</strong>: Modify the PRD, explicitly listing &quot;Non-goals&quot; (such as &quot;No user login support,&quot; &quot;No multi-user collaboration&quot;), then re-execute the Code stage.</p><h3 id="common-error-4-excessive-token-consumption" tabindex="-1">Common Error 4: Excessive Token Consumption <a class="header-anchor" href="#common-error-4-excessive-token-consumption" aria-label="Permalink to &quot;Common Error 4: Excessive Token Consumption&quot;">​</a></h3><p><strong>Symptom</strong>: Token consumption spikes in the later stages of pipeline execution, and AI assistant responses become slow.</p><p><strong>Cause</strong>: Executing multiple stages in the same session causes context to continuously accumulate.</p><p><strong>Solution</strong>: <strong>Always choose &quot;Continue in New Session&quot;</strong> (Option 2), giving each stage a clean context.</p><h2 id="lesson-summary" tabindex="-1">Lesson Summary <a class="header-anchor" href="#lesson-summary" aria-label="Permalink to &quot;Lesson Summary&quot;">​</a></h2><ul><li>The pipeline includes 7 stages: Bootstrap → PRD → UI → Tech → Code → Validation → Preview</li><li>Pause for confirmation after each stage to ensure output meets expectations</li><li>Sisyphus scheduler coordinates Agent execution, manages state and permissions</li><li>Capability boundary matrix prevents Agents from overstepping, ensuring separation of concerns</li><li>Choosing &quot;Continue in New Session&quot; can significantly save tokens</li></ul><h2 id="next-lesson-preview" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview" aria-label="Permalink to &quot;Next Lesson Preview&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../../platforms/claude-code/">Claude Code Integration Guide</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>How to configure Claude Code permissions</li><li>How to run the pipeline</li><li>Claude Code best practices</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-29</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Line Range</th></tr></thead><tbody><tr><td>Pipeline definition</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/pipeline.yaml" target="_blank" rel="noreferrer"><code>pipeline.yaml</code></a></td><td>1-111</td></tr><tr><td>Scheduler core</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/orchestrator.checkpoint.md" target="_blank" rel="noreferrer"><code>agents/orchestrator.checkpoint.md</code></a></td><td>1-302</td></tr><tr><td>Project README</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/README.md" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>1-253</td></tr></tbody></table><p><strong>Key Constants</strong>:</p><ul><li>Pipeline mode: <code>checkpoint</code> (checkpoint mode, pause for confirmation after each stage)</li></ul><p><strong>Key Agent Definitions</strong>:</p><ul><li><strong>Bootstrap Agent</strong>: Uses <code>superpowers:brainstorm</code> skill, generates <code>input/idea.md</code></li><li><strong>PRD Agent</strong>: Reads <code>input/idea.md</code>, generates <code>artifacts/prd/prd.md</code></li><li><strong>UI Agent</strong>: Uses <code>ui-ux-pro-max</code> skill, generates <code>artifacts/ui/ui.schema.yaml</code> and preview page</li><li><strong>Tech Agent</strong>: Generates <code>artifacts/tech/tech.md</code> and <code>artifacts/backend/prisma/schema.prisma</code></li><li><strong>Code Agent</strong>: Generates <code>artifacts/backend/</code> and <code>artifacts/client/</code> based on UI, Tech, Schema</li><li><strong>Validation Agent</strong>: Validates code quality, generates <code>artifacts/validation/report.md</code></li><li><strong>Preview Agent</strong>: Generates <code>artifacts/preview/README.md</code></li></ul></details>`,159)])])}const g=e(s,[["render",o]]);export{h as __pageData,g as default};
